        <div className="space-y-2">
          <label className="block text-xs font-bold text-stone-500 uppercase tracking-wider ml-1">
            {tGoals('targetTimeOptional')}
          </label>
          <div className="grid grid-cols-3 gap-2">
            <div className="relative">
              <Input
                id="request-goal-target_time_hours"
                name="target_time_hours"
                type="number"
                min={0}
                max={99}
                placeholder=""
                className="text-center pr-9"
                aria-label={tGoals('result.hours')}
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-stone-500 pointer-events-none">
                {tGoals('result.unitHours')}
              </span>
            </div>
            <div className="relative">
              <Input
                id="request-goal-target_time_minutes"
                name="target_time_minutes"
                type="number"
                min={0}
                max={59}
                placeholder=""
                className="text-center pr-10"
                aria-label={tGoals('result.minutes')}
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-stone-500 pointer-events-none">
                {tGoals('result.unitMinutes')}
              </span>
            </div>
            <div className="relative">
              <Input
                id="request-goal-target_time_seconds"
                name="target_time_seconds"
                type="number"
                min={0}
                max={59}
                placeholder=""
                className="text-center pr-8"
                aria-label={tGoals('result.seconds')}
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-stone-500 pointer-events-none">
                {tGoals('result.unitSeconds')}
              </span>
            </div>
          </div>
        </div>

        {isPast && (
          <>
            <div>
              <label className="block text-sm font-medium text-stone-700 mb-2">
                {tGoals('result.time')} <span className="text-palette-danger">*</span>
              </label>
              <div className="grid grid-cols-3 gap-3">
                <div className="relative">
                  <Input
                    name="result_time_hours"
                    type="number"
                    min={0}
                    max={99}
                    placeholder="0"
                    className="text-center pr-9"
                    aria-label={tGoals('result.hours')}
                  />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-stone-500 pointer-events-none">
                    {tGoals('result.unitHours')}
                  </span>
                </div>
                <div className="relative">
                  <Input
                    name="result_time_minutes"
                    type="number"
                    min={0}
                    max={59}
                    placeholder="0"
                    className="text-center pr-10"
                    aria-label={tGoals('result.minutes')}
                  />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-stone-500 pointer-events-none">
                    {tGoals('result.unitMinutes')}
                  </span>
                </div>
                <div className="relative">
                  <Input
                    name="result_time_seconds"
                    type="number"
                    min={0}
                    max={59}
                    placeholder="0"
                    className="text-center pr-8"
                    aria-label={tGoals('result.seconds')}
                  />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-stone-500 pointer-events-none">
                    {tGoals('result.unitSeconds')}
                  </span>
                </div>
              </div>
            </div>
            <Input
              name="result_place"
              label={tGoals('result.placeOptional')}
              type="number"
              min={1}
              placeholder="42"
            />
            <Textarea
              name="result_note"
              label={tGoals('result.noteOptional')}
              placeholder={tGoals('result.notePlaceholder')}
              rows={3}
            />
          </>
        )}

        {state?.error && (
          <p className="text-sm text-palette-danger font-medium" role="alert">
            {state.error}
          </p>
        )}
      </form>

      {showDatePickerPopup && datePickerAnchor && typeof document !== 'undefined' &&
        createPortal(
          <>
            <div
              className="fixed z-[210] shadow-xl"
              ref={datePickerPopupRef}
              style={(() => {
                const POPUP_W = 320
                const POPUP_H = 360
                const M = 8
                const vw = typeof window !== 'undefined' ? window.innerWidth : 1200
                const vh = typeof window !== 'undefined' ? window.innerHeight : 800
                const left = Math.max(M, Math.min(datePickerAnchor.left, vw - POPUP_W - M))
                const preferBottomTop = datePickerAnchor.bottom + M
                const fitsBelow = preferBottomTop + POPUP_H <= vh - M
                const top = fitsBelow
                  ? preferBottomTop
                  : Math.max(M, datePickerAnchor.top - M - POPUP_H)
                return { top, left, maxHeight: `calc(100vh - ${M * 2}px)` }
              })()}
            >
              <DatePickerPopup
                value={selectedDate || today()}
                onChange={(dateStr) => {
                  setSelectedDate(dateStr)
                  closeDatePicker()
                }}
                locale={localeForPicker}
                monthDropdownId="request-goal-date-picker-month"
              />
            </div>
          </>,
          document.body
        )}
    </Modal>
  )
}

import Link from 'next/link'
import { createClient } from '@/utils/supabase/server'
import { getCurrentUserWithProfile } from '@/utils/auth'
import { redirect } from 'next/navigation'
import { CoachAthleteCalendarPage } from '@/components/CoachAthleteCalendarPage'
import type { Workout, Goal, ImportedActivityWeeklyTotal, WorkoutWeeklyTotal, AthleteAvailabilitySlot } from '@/types/database'
import { getWeekMonday } from '@/lib/dateUtils'
import { getDisplayName } from '@/lib/displayName'
import { getEffectiveWeeklyTotalsFait } from '@/app/[locale]/dashboard/workouts/actions'
import { getAvailabilityForDateRange } from '@/app/[locale]/dashboard/availability/actions'

type PageProps = { params: Promise<{ athleteId: string }> }

export default async function AthleteCalendarPage({ params }: PageProps) {
  const { athleteId } = await params
  const current = await getCurrentUserWithProfile()

  if (current.profile.role !== 'coach') {
    redirect('/dashboard')
  }

  const supabase = await createClient()
  const { data: athleteProfile } = await supabase
    .from('profiles')
    .select('user_id, email, coach_id, first_name, last_name, avatar_url')
    .eq('user_id', athleteId)
    .single()

  if (!athleteProfile || athleteProfile.user_id === current.id || athleteProfile.coach_id !== current.id) {
    redirect('/dashboard/athletes')
  }

  const today = new Date()
  const currentMonday = getWeekMonday(today)
  // Charger 5 semaines : S-2, S-1, S, S+1, S+2
  const startMonday = new Date(currentMonday)
  startMonday.setDate(startMonday.getDate() - 14) // S-2
  const endSunday = new Date(currentMonday)
  endSunday.setDate(endSunday.getDate() + 14 + 6) // S+2

  const startStr = startMonday.toISOString().slice(0, 10)
  const endStr = endSunday.toISOString().slice(0, 10)
  // Calculer les lundis des 5 semaines pour les totaux
  const weekMondays: string[] = []
  for (let offset = -2; offset <= 2; offset++) {
    const weekMonday = new Date(currentMonday)
    weekMonday.setDate(weekMonday.getDate() + offset * 7)
    weekMondays.push(weekMonday.toISOString().slice(0, 10))
  }

  const [workoutsResult, goalsResult, workoutTotalsResult, effectiveFaitResult, initialAvailabilities] = await Promise.all([
    supabase
      .from('workouts')
      .select('*')
      .eq('athlete_id', athleteId)
      .gte('date', startStr)
      .lte('date', endStr)
      .order('date')
      .order('created_at'),
    supabase
      .from('goals')
      .select('*')
      .eq('athlete_id', athleteId)
      .order('date', { ascending: true }),
    supabase
      .from('workout_weekly_totals')
      .select('*')
      .eq('athlete_id', athleteId)
      .in('week_start', weekMondays)
      .order('week_start')
      .order('sport_type'),
    getEffectiveWeeklyTotalsFait(athleteId, weekMondays[0], weekMondays[weekMondays.length - 1]),
    getAvailabilityForDateRange(athleteId, startStr, endStr),
  ])
  const workouts = workoutsResult.data
  const goals = goalsResult.data
  const initialWorkoutTotals = workoutTotalsResult.data ?? []
  const initialWeeklyTotals = effectiveFaitResult.weeklyTotals ?? []

  const displayName = getDisplayName(athleteProfile, athleteProfile.email)

  return (
    <CoachAthleteCalendarPage
      athleteId={athleteId}
      athleteEmail={athleteProfile.email}
      athleteName={displayName}
      athleteAvatarUrl={athleteProfile.avatar_url}
      initialWorkouts={(workouts ?? []) as Workout[]}
      initialWeeklyTotals={(initialWeeklyTotals ?? []) as ImportedActivityWeeklyTotal[]}
      initialWorkoutTotals={(initialWorkoutTotals ?? []) as WorkoutWeeklyTotal[]}
      initialAvailabilities={(initialAvailabilities ?? []) as AthleteAvailabilitySlot[]}
      goals={(goals ?? []) as Goal[]}
      canEdit={true}
      pathToRevalidate={`/dashboard/athletes/${athleteId}`}
    />
  )
}

'use client'

import { useState, useTransition, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { useTranslations, useLocale } from 'next-intl'
import { Button } from '@/components/Button'
import { Modal } from '@/components/Modal'
import { Textarea } from '@/components/Textarea'
import { upsertCoachRating } from './actions'

type CoachRatingFormProps = {
  coachId: string
  initialRating: number | null
  initialComment: string
}

export function CoachRatingForm({ coachId, initialRating, initialComment }: CoachRatingFormProps) {
  const t = useTranslations('myCoach.rating')
  const locale = useLocale()
  const [rating, setRating] = useState<number>(initialRating ?? 0)
  const [comment, setComment] = useState(initialComment ?? '')
  const [error, setError] = useState<string | null>(null)
  const [showSavedFeedback, setShowSavedFeedback] = useState(false)
  const [isPending, startTransition] = useTransition()
  const [unsavedChangesModalOpen, setUnsavedChangesModalOpen] = useState(false)
  const [pendingNavigation, setPendingNavigation] = useState<string | null>(null)
  const [isSavingBeforeLeave, setIsSavingBeforeLeave] = useState(false)
  const isSubmittingRef = useRef(false)
  const router = useRouter()

  const initialRatingValue = initialRating ?? 0
  const initialCommentValue = initialComment ?? ''
  const initialSignature = `${coachId}|${initialRatingValue}|${initialCommentValue.trim()}`
  // Valeurs de référence après un save réussi (comme ProfileForm)
  const [savedState, setSavedState] = useState<{
    signature: string
    values: { rating: number; comment: string }
  } | null>(null)
  const refForComparison =
    savedState?.signature === initialSignature
      ? savedState.values
      : { rating: initialRatingValue, comment: initialCommentValue }
  const hasUnsavedChanges =
    rating !== refForComparison.rating || comment.trim() !== refForComparison.comment.trim()

  const clearFeedbackOnInput = () => {
    if (showSavedFeedback) setShowSavedFeedback(false)
    if (error) setError(null)
  }

  const handleRatingChange = (value: number) => {
    clearFeedbackOnInput()
    setRating(value)
  }

  const handleCommentChange = (value: string) => {
    clearFeedbackOnInput()
    setComment(value)
  }

  // beforeunload : avertir si modifications non enregistrées
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (!isSubmittingRef.current && hasUnsavedChanges) {
        e.preventDefault()
        e.returnValue = ''
      }
    }
    window.addEventListener('beforeunload', handleBeforeUnload)
    return () => window.removeEventListener('beforeunload', handleBeforeUnload)
  }, [hasUnsavedChanges])

  // Intercepter les clics sur les liens (même modale que Mes informations)
  useEffect(() => {
    const handleLinkClick = (e: MouseEvent) => {
      if (isSubmittingRef.current) return
      const target = e.target as HTMLElement
      const link = target.closest('a')
      if (!link) return
      const href = link.getAttribute('href')
      if (!href || href.startsWith('#') || href.startsWith('javascript:')) return
      if (hasUnsavedChanges) {
        e.preventDefault()
        setPendingNavigation(href)
        setUnsavedChangesModalOpen(true)
      }
    }
    document.addEventListener('click', handleLinkClick, true)
    return () => document.removeEventListener('click', handleLinkClick, true)
  }, [hasUnsavedChanges])

  // Retour navigateur
  useEffect(() => {
    const handlePopState = () => {
      if (hasUnsavedChanges && !isSubmittingRef.current) {
        const confirmed = window.confirm(
          t('unsavedChangesAlert')
        )
        if (!confirmed) {
          window.history.pushState(null, '', window.location.href)
        }
      }
    }
    window.addEventListener('popstate', handlePopState)
    return () => window.removeEventListener('popstate', handlePopState)
  }, [hasUnsavedChanges])

  // Échap pour fermer la modale
  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && unsavedChangesModalOpen && !isSavingBeforeLeave) {
        setUnsavedChangesModalOpen(false)
        setPendingNavigation(null)
      }
    }
    if (unsavedChangesModalOpen) {
      document.addEventListener('keydown', handleEscape)
      document.body.style.overflow = 'hidden'
    }
    return () => {
      document.removeEventListener('keydown', handleEscape)
      document.body.style.overflow = ''
    }
  }, [unsavedChangesModalOpen, isSavingBeforeLeave])

  const handleSaveAndLeave = async () => {
    if (rating < 1 || rating > 5) return
    setIsSavingBeforeLeave(true)
    const result = await upsertCoachRating(coachId, rating, comment, locale)
    setIsSavingBeforeLeave(false)
    if (!result.error) {
      setUnsavedChangesModalOpen(false)
      if (pendingNavigation) router.push(pendingNavigation)
      setPendingNavigation(null)
      router.refresh()
    }
  }

  const handleLeaveWithoutSaving = () => {
    setUnsavedChangesModalOpen(false)
    if (pendingNavigation) router.push(pendingNavigation)
    setPendingNavigation(null)
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (rating < 1 || rating > 5) {
      setError(t('validationError'))
      return
    }
    setError(null)
    isSubmittingRef.current = true
    startTransition(async () => {
      const result = await upsertCoachRating(coachId, rating, comment, locale)
      isSubmittingRef.current = false
      if (result.error) {
        setError(result.error)
        return
      }
      // Comme ProfileForm : mettre à jour les refs pour que hasUnsavedChanges passe à false
      // (sinon le useEffect "clear on hasUnsavedChanges" efface immédiatement le feedback)
      setSavedState({
        signature: initialSignature,
        values: { rating, comment },
      })
      setShowSavedFeedback(true)
      setTimeout(() => {
        setShowSavedFeedback(false)
        router.refresh()
      }, 2500)
    })
  }

  return (
    <>
    <form onSubmit={handleSubmit} className="space-y-4">
      {/* En-tête : titre à gauche, bouton à droite */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
        <h2 className="text-base font-semibold text-stone-900">{t('title')}</h2>
        <Button
          type="submit"
          variant="primary"
          disabled={!hasUnsavedChanges || isPending || rating < 1}
          loading={isPending}
          loadingText={t('saving')}
          success={showSavedFeedback}
          error={!!error}
        >
          {t('save')}
        </Button>
      </div>
      {error && (
        <p className="text-sm text-palette-danger-dark -mt-2 mb-2" role="alert">
          {error}
        </p>
      )}
      <div>
        <p className="text-sm font-medium text-stone-700 mb-2">{t('yourRating')}</p>
        <div className="flex gap-1" role="group" aria-label={t('ratingLabel')}>
          {[1, 2, 3, 4, 5].map((value) => (
            <button
              key={value}
              type="button"
              onClick={() => handleRatingChange(value)}
              className="p-1 rounded focus:outline-none focus:ring-2 focus:ring-palette-olive focus:ring-offset-1 transition-transform hover:scale-110"
              aria-label={t('starLabel', { value })}
              aria-pressed={rating === value}
            >
              <span
                className={`text-2xl ${
                  value <= rating ? 'text-amber-400' : 'text-stone-200'
                }`}
                aria-hidden
              >
                ★
              </span>
            </button>
          ))}
        </div>
        <p className="text-xs text-stone-500 mt-1">{rating > 0 ? t('ratingDisplay', { rating }) : t('clickToChoose')}</p>
      </div>

      <Textarea
        id="rating-comment"
        label={t('commentLabel')}
        value={comment}
        onChange={(e) => handleCommentChange(e.target.value)}
        rows={3}
        placeholder={t('commentPlaceholder')}
      />
    </form>

    <Modal
      isOpen={unsavedChangesModalOpen}
      onClose={() => !isSavingBeforeLeave && (setUnsavedChangesModalOpen(false), setPendingNavigation(null))}
      title={t('unsavedChangesModal.title')}
      size="md"
      titleId="coach-rating-unsaved-title"
      disableOverlayClose={isSavingBeforeLeave}
      disableEscapeClose={isSavingBeforeLeave}
      footer={
        <div className="flex gap-3 w-full">
          <Button
            type="button"
            variant="muted"
            onClick={handleLeaveWithoutSaving}
            disabled={isSavingBeforeLeave}
            className="flex-1"
          >
            {t('unsavedChangesModal.leaveWithoutSaving')}
          </Button>
          <Button
            type="button"
            variant="primary"
            onClick={handleSaveAndLeave}
            disabled={isSavingBeforeLeave || rating < 1}
            loading={isSavingBeforeLeave}
            loadingText={t('saving')}
            className="flex-1"
          >
            {t('unsavedChangesModal.saveAndLeave')}
          </Button>
        </div>
      }
    >
      <div className="px-6 py-4">
        <p className="text-sm text-stone-600">
          {t('unsavedChangesModal.message')}
        </p>
      </div>
    </Modal>
    </>
  )
}

'use client'

import { Button } from '@/components/Button'
import { useRouter, useSearchParams } from 'next/navigation'
import { useState } from 'react'
import { useTranslations, useLocale } from 'next-intl'
import { syncStravaLastWeek, disconnectStrava } from './actions'
import type { AthleteConnectedService } from '@/types/database'

type StravaDevicesSectionProps = {
  userId: string
  connected: boolean
  connection: Pick<AthleteConnectedService, 'id' | 'provider' | 'strava_athlete_id' | 'created_at'> | null
}

export function StravaDevicesSection({ userId, connected, connection }: StravaDevicesSectionProps) {
  const t = useTranslations('devices')
  const locale = useLocale()
  const router = useRouter()
  const searchParams = useSearchParams()
  const [syncing, setSyncing] = useState(false)
  const [disconnecting, setDisconnecting] = useState(false)
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null)

  const urlMessage = searchParams.get('strava') === 'connected'
    ? t('messages.connected')
    : searchParams.get('error') === 'strava_invalid'
      ? t('messages.errorInvalid')
      : searchParams.get('error') === 'strava_config'
        ? t('messages.errorConfig')
        : searchParams.get('error') === 'strava_token'
          ? t('messages.errorToken')
          : searchParams.get('error') === 'strava_save'
            ? t('messages.errorSave')
            : null

  // Traduire les messages statiques en dehors des handlers
  const confirmText = t('disconnectConfirm')
  const disconnectedText = t('messages.disconnected')

  const handleSync = async () => {
    setMessage(null)
    setSyncing(true)
    const result = await syncStravaLastWeek(userId, locale)
    setSyncing(false)
    if (result.error) {
      setMessage({ type: 'error', text: result.error })
    } else {
      const successText = result.imported !== undefined
        ? t('messages.importSuccess', { count: result.imported })
        : t('messages.importComplete')
      setMessage({
        type: 'success',
        text: successText,
      })
      router.refresh()
    }
  }

  const handleDisconnect = async () => {
    if (!confirm(confirmText)) return
    setMessage(null)
    setDisconnecting(true)
    const result = await disconnectStrava(userId, locale)
    setDisconnecting(false)
    if (result.error) {
      setMessage({ type: 'error', text: result.error })
    } else {
      setMessage({ type: 'success', text: disconnectedText })
      router.refresh()
    }
  }

  const ConnectWithStravaButton = () => (
    <Button href="/api/auth/strava" variant="strava" aria-label={t('connectStrava')}>
      {t('connectStrava')}
    </Button>
  )

  return (
    <div className="max-w-3xl mx-auto">
      <section className="bg-white rounded-2xl shadow-xl overflow-hidden border border-stone-100">
        <div className="px-8 py-6">
          <div className="flex items-start justify-between gap-6 flex-wrap">
            <div className="flex min-w-0 flex-1 items-center gap-4">
              <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-xl bg-palette-strava">
                <img
                  src="/strava-icon.svg"
                  alt="Strava"
                  width={32}
                  height={32}
                  className="object-contain"
                />
              </div>
              <div className="min-w-0">
                <h2 className="text-base font-bold text-stone-900 mb-1">Strava</h2>
                <p className="text-sm text-stone-600">
                  {connected
                    ? t('connectedDescription')
                    : t('notConnectedDescription')}
                </p>
              </div>
            </div>
            <div className="flex shrink-0 flex-col sm:flex-row gap-3 items-stretch sm:items-center">
              {connected ? (
                <>
                  <Button
                    href="/api/auth/strava"
                    variant="muted"
                  >
                    {t('reconnect')}
                  </Button>
                  <Button
                    type="button"
                    variant="strava"
                    onClick={handleSync}
                    disabled={syncing}
                    loading={syncing}
                    loadingText={t('syncInProgress')}
                  >
                    {t('syncActivities')}
                  </Button>
                  <Button
                    type="button"
                    variant="danger"
                    onClick={handleDisconnect}
                    disabled={disconnecting}
                    loading={disconnecting}
                    loadingText={t('disconnecting')}
                  >
                    {t('disconnectStrava')}
                  </Button>
                </>
              ) : (
                <ConnectWithStravaButton />
              )}
            </div>
          </div>
          {(urlMessage || message) && (
            <div
              className={`mt-6 rounded-lg px-4 py-3 text-sm ${
                message?.type === 'error' || (searchParams.get('error') && !urlMessage)
                  ? 'bg-palette-danger-light text-palette-danger-dark border border-palette-danger'
                  : 'bg-palette-forest-dark/10 text-palette-forest-dark border border-palette-forest-dark/20'
              }`}
            >
              {message ? message.text : urlMessage}
            </div>
          )}
        </div>
      </section>
    </div>
  )
}

import type { Metadata } from 'next'
import { redirect } from 'next/navigation'
import { getCurrentUserWithProfile } from '@/utils/auth'
import { getTranslations } from 'next-intl/server'
import { DashboardPageShell } from '@/components/DashboardPageShell'
import { StravaDevicesSection } from './StravaDevicesSection'
import { getStravaConnection } from './actions'

export async function generateMetadata({ params }: { params: Promise<{ locale: string }> }): Promise<Metadata> {
  const { locale } = await params
  const t = await getTranslations({ locale, namespace: 'metadata' })
  return {
    title: t('devicesTitle')
  }
}

export default async function DevicesPage({ params }: { params: Promise<{ locale: string }> }) {
  const { locale } = await params
  const t = await getTranslations({ locale, namespace: 'devices' })
  const current = await getCurrentUserWithProfile()
  if (current.profile.role !== 'athlete') {
    redirect('/dashboard')
  }

  const result = await getStravaConnection(current.id)
  const connected = result.connected && !!result.connection
  const connection = result.connection ?? null

  return (
    <DashboardPageShell>
      <StravaDevicesSection
        userId={current.id}
        connected={connected}
        connection={connection}
      />
    </DashboardPageShell>
  )
}

