import { createClient } from '@/utils/supabase/server'
import { redirect } from 'next/navigation'
import { getTranslations, getLocale } from 'next-intl/server'

export type UpdatePasswordState = {
  error?: string
  success?: string
}

/** Mettre à jour le mot de passe après réinitialisation. */
export async function updatePassword(
  _prevState: UpdatePasswordState,
  formData: FormData
): Promise<UpdatePasswordState> {
  const password = formData.get('password') as string
  const confirmPassword = formData.get('confirmPassword') as string

  const locale = await getLocale()
  const [t, tErrors] = await Promise.all([
    getTranslations({ locale, namespace: 'auth.errors' }),
    getTranslations({ locale, namespace: 'errors' }),
  ])

  if (!password || !confirmPassword) {
    return { error: t('bothFieldsRequired') }
  }

  if (password !== confirmPassword) {
    return { error: t('passwordMismatch') }
  }

  if (password.length < 6) {
    return { error: t('passwordMinLength') }
  }

  const supabase = await createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) {
    return { error: t('sessionExpiredReset') }
  }

  const { error } = await supabase.auth.updateUser({
    password: password,
  })

  if (error) {
    return { error: tErrors('supabaseGeneric') }
  }

  return { success: t('passwordUpdatedSuccess') }
}

import type { SportType } from '@/types/database'
import { SPORT_ICONS, SPORT_CARD_STYLES } from '@/lib/sportStyles'

type ActivityTileBaseProps = {
  /** Titre principal de l'activité */
  title: string
  /** Date de l'activité (affichée en bas) */
  date?: string
  /** Fonction appelée au clic sur la tuile */
  onClick?: () => void
  /** Classes CSS supplémentaires */
  className?: string
}

type WorkoutTileProps = ActivityTileBaseProps & {
  type: 'workout'
  /** Type de sport (détermine l'icône et la couleur de bordure) */
  sportType: SportType
  /** Métadonnées optionnelles (ex: "45'", "10 km", "120m D+") */
  metadata?: string[]
}

type StravaActivityTileProps = ActivityTileBaseProps & {
  type: 'strava'
  /** Label du type d'activité Strava (ex: "Run", "Ride") */
  activityLabel: string
  /** Métadonnées optionnelles (ex: "10.5 km", "150m D+") */
  metadata?: string[]
}

type GoalTileProps = ActivityTileBaseProps & {
  type: 'goal'
  /** Distance de la course (en km) */
  distance: number
  /** Si true, objectif principal (badge amber), sinon secondaire (badge sage) */
  isPrimary: boolean
  /** Si true, affiche la bande grise (résultat) sans contour */
  isResult?: boolean
}

export type ActivityTileProps = WorkoutTileProps | StravaActivityTileProps | GoalTileProps

/**
 * Composant tuile d'activité unifié pour :
 * - Entraînements planifiés (workout)
 * - Activités Strava importées (strava)
 * - Objectifs de course (goal)
 * 
 * Design inspiré du style Strava avec bordure gauche colorée et badge.
 * 
 * @example
 * // Entraînement
 * <ActivityTile
 *   type="workout"
 *   sportType="course"
 *   title="Sortie longue"
 *   metadata={["1h30", "15 km", "200m D+"]}
 *   date="Lun. 12 fév."
 *   onClick={() => console.log('click')}
 * />
 * 
 * @example
 * // Activité Strava
 * <ActivityTile
 *   type="strava"
 *   activityLabel="Run"
 *   title="Morning run"
 *   metadata={["10.5 km", "150m D+"]}
 *   date="Mar. 13 fév."
 *   onClick={() => console.log('click')}
 * />
 * 
 * @example
 * // Objectif
 * <ActivityTile
 *   type="goal"
 *   isPrimary={true}
 *   title="Marathon de Paris"
 *   distance={42.2}
 *   date="Dim. 7 avr."
 *   onClick={() => console.log('click')}
 * />
 */
export function ActivityTile(props: ActivityTileProps) {
  const { title, date, onClick, className = '' } = props

  // Rendu entraînement planifié
  if (props.type === 'workout') {
    const { sportType, metadata = [] } = props
    const style = SPORT_CARD_STYLES[sportType]
    const SportIcon = SPORT_ICONS[sportType]

    return (
      <button
        type="button"
        onClick={onClick}
        className={`w-full text-left rounded-lg border border-l-4 ${style.borderLeft} border-stone-200 bg-white p-3 shadow-sm training-card flex items-center gap-3 ${className}`}
      >
        <span className={`shrink-0 inline-flex ${style.badge} ${style.badgeBg} px-2 py-1 rounded`}>
          <SportIcon className="w-4 h-4" />
        </span>
        <div className="min-w-0 flex-1">
          <div className="font-semibold text-stone-900 break-words">{title}</div>
          {(metadata.length > 0 || date) && (
            <div className="text-xs text-stone-500 font-semibold mt-0.5 flex items-center gap-1.5 flex-wrap">
              {date && <span>{date}</span>}
              {date && metadata.length > 0 && <span className="text-sm font-bold">·</span>}
              {metadata.map((item, idx) => (
                <span key={idx} className="contents">
                  <span>{item}</span>
                  {idx < metadata.length - 1 && <span className="text-sm font-bold">·</span>}
                </span>
              ))}
            </div>
          )}
        </div>
      </button>
    )
  }

  // Rendu activité Strava
  if (props.type === 'strava') {
    const { activityLabel, metadata = [] } = props

    return (
      <button
        type="button"
        onClick={onClick}
        className={`w-full text-left rounded-lg border border-l-4 border-l-palette-strava border-stone-200 bg-white p-3 shadow-sm training-card flex items-center gap-3 ${className}`}
      >
        <img src="/strava-icon.svg" alt="" className="h-5 w-5 shrink-0" aria-hidden />
        <div className="min-w-0 flex-1">
          <div className="flex items-center gap-2 mb-0.5">
            <span className="text-[10px] font-bold uppercase text-palette-strava bg-orange-100 px-1.5 py-0.5 rounded leading-none">
              {activityLabel}
            </span>
          </div>
          <div className="font-semibold text-stone-900 break-words">{title}</div>
          {(metadata.length > 0 || date) && (
            <div className="text-xs text-stone-500 font-semibold mt-0.5 flex items-center gap-1.5 flex-wrap">
              {date && <span>{date}</span>}
              {date && metadata.length > 0 && <span className="text-sm font-bold">·</span>}
              {metadata.map((item, idx) => (
                <span key={idx} className="contents">
                  <span>{item}</span>
                  {idx < metadata.length - 1 && <span className="text-sm font-bold">·</span>}
                </span>
              ))}
            </div>
          )}
        </div>
      </button>
    )
  }

  // Rendu objectif de course
  if (props.type === 'goal') {
    const { distance, isPrimary, isResult } = props
    const borderColor = isResult ? 'border-l-stone-400' : (isPrimary ? 'border-l-palette-amber' : 'border-l-palette-sage')
    const badgeColor = isPrimary ? 'text-palette-amber bg-white' : 'text-palette-sage bg-white'
    const borderClasses = isResult ? 'border-0 border-l-4' : 'border border-l-4 border-stone-200'

    return (
      <button
        type="button"
        onClick={onClick}
        className={`w-full text-left rounded-lg ${borderClasses} ${borderColor} bg-white p-3 shadow-sm training-card flex items-center gap-3 ${className}`}
      >
        <span className={`shrink-0 inline-flex items-center justify-center ${badgeColor} px-2 py-1 rounded`}>
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="12" r="10" />
            <circle cx="12" cy="12" r="6" />
            <circle cx="12" cy="12" r="2" />
          </svg>
        </span>
        <div className="min-w-0 flex-1">
          <div className="font-semibold text-stone-900 break-words">{title}</div>
          <div className="text-xs text-stone-500 font-semibold mt-0.5 flex items-center gap-1.5 flex-wrap">
            {date && <span>{date}</span>}
            {date && <span className="text-sm font-bold">·</span>}
            <span>{distance} km</span>
          </div>
        </div>
      </button>
    )
  }

  return null
}

'use client'

/**
 * AthleteTile — Tuile athlète du design system.
 * Même structure visuelle que CoachTile : carte rounded-2xl, header (avatar + nom),
 * badges sports, zone contenu (objectif + planifié jusqu’à), footer d’action.
 * Utilisé dans la page « Mes athlètes » (vue coach).
 */

import { Badge } from '@/components/Badge'
import { getInitials } from '@/lib/stringUtils'

export type AthleteTileNextGoal = {
  date: string
  raceName: string
}

export type AthleteTileProps = {
  /** URL de l’avatar ou null pour initiales */
  avatarUrl?: string | null
  /** Nom affiché (fallback: email) */
  displayName: string
  /** Sports pratiqués (valeurs pour Badge) */
  practicedSports: string[]
  /** Prochain objectif (date + nom course) */
  nextGoal?: AthleteTileNextGoal | null
  /** Date jusqu’à laquelle le planning est planifié */
  plannedUntil?: string | null
  /** Indicateur à jour / en retard */
  isUpToDate?: boolean
  /** Contenu du footer (lien « Voir le planning », etc.) */
  footer: React.ReactNode
  /** Titre de la souscription active (affiché sous le nom avec flèche, clic → détail) */
  subscriptionTitle?: string | null
  /** Appelé au clic sur la ligne souscription (ouvrir détail en modale) */
  onSubscriptionClick?: () => void
  /** Labels optionnels (pour i18n côté appelant) */
  labels?: {
    nextGoal?: string
    noGoal?: string
    plannedUntil?: string
    upToDate?: string
    late?: string
  }
}

const cardClasses =
  'bg-white rounded-2xl border border-stone-200 shadow-sm hover:shadow-lg hover:border-palette-forest-dark/30 transition-all flex flex-col overflow-hidden group h-full'

export function AthleteTile({
  avatarUrl,
  displayName,
  practicedSports,
  nextGoal,
  plannedUntil,
  isUpToDate = true,
  footer,
  subscriptionTitle,
  onSubscriptionClick,
  labels = {},
}: AthleteTileProps) {
  const {
    nextGoal: nextGoalLabel = 'Prochain objectif',
    noGoal: noGoalLabel = 'Aucun objectif',
    plannedUntil: plannedUntilLabel = 'Planifié jusqu\'au',
    upToDate: upToDateLabel = 'À jour',
    late: lateLabel = 'En retard',
  } = labels

  return (
    <article className={cardClasses}>
      <div className="p-6 flex flex-col flex-grow">
        {/* Header: avatar + nom (même disposition que CoachTile) */}
        <div className="flex items-start justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="relative">
              {avatarUrl?.trim() ? (
                <img
                  src={avatarUrl}
                  alt=""
                  className="w-12 h-12 rounded-full object-cover ring-2 ring-stone-100 group-hover:ring-palette-forest-dark/20 transition-all"
                />
              ) : (
                <div className="w-12 h-12 rounded-full bg-palette-olive text-white flex items-center justify-center text-base font-bold ring-2 ring-stone-100 group-hover:ring-palette-forest-dark/20 transition-all">
                  {getInitials(displayName)}
                </div>
              )}
            </div>
            <div className="min-w-0 flex-1">
              <h3 className="font-bold text-lg leading-tight text-stone-900 group-hover:text-palette-forest-dark transition-colors">
                {displayName}
              </h3>
              {subscriptionTitle && (
                onSubscriptionClick ? (
                  <button
                    type="button"
                    onClick={onSubscriptionClick}
                    className="mt-1.5 flex items-center gap-1 text-sm font-medium text-palette-forest-dark hover:text-palette-forest-darker transition-colors text-left w-full min-w-0"
                  >
                    <span className="truncate">{subscriptionTitle}</span>
                    <svg className="w-4 h-4 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden>
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                    </svg>
                  </button>
                ) : (
                  <p className="mt-1.5 text-sm font-medium text-palette-forest-dark truncate">
                    {subscriptionTitle}
                  </p>
                )
              )}
            </div>
          </div>
        </div>

        {/* Tags sports (même ligne que CoachTile) */}
        <div className="flex flex-wrap gap-2 mb-4">
          {practicedSports.map((sportValue) => (
            <Badge key={sportValue} sport={sportValue as Parameters<typeof Badge>[0]['sport']} />
          ))}
        </div>

        {/* Contenu: objectif + planifié (grille 2 colonnes, comme la tuile actuelle mais dans le même style carte) */}
        <div className="grid grid-cols-2 gap-4 text-sm flex-1">
          <div>
            <p className="text-xs font-bold uppercase tracking-wider text-stone-500">{nextGoalLabel}</p>
            <p className="text-stone-900 mt-0.5">
              {nextGoal ? `${nextGoal.date} · ${nextGoal.raceName}` : noGoalLabel}
            </p>
          </div>
          <div>
            <p className="text-xs font-bold uppercase tracking-wider text-stone-500">{plannedUntilLabel}</p>
            <p className="text-stone-900 font-semibold mt-0.5 text-sm">
              {plannedUntil ?? '—'}
            </p>
            <div className="flex items-center gap-1 mt-0.5">
              <span
                className={`w-1.5 h-1.5 rounded-full shrink-0 ${
                  isUpToDate ? 'bg-emerald-500' : 'bg-red-400'
                }`}
              />
              <span
                className={`text-[10px] font-medium ${
                  isUpToDate ? 'text-stone-500' : 'text-red-400'
                }`}
              >
                {isUpToDate ? upToDateLabel : lateLabel}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Footer (même zone que CoachTile) */}
      <div className="p-4 border-t border-stone-100 bg-stone-50 mt-auto w-full">
        {footer}
      </div>
    </article>
  )
}

'use client'

import { useState, useRef, useEffect } from 'react'
import { createPortal } from 'react-dom'
import { useFormStatus } from 'react-dom'
import { useActionState } from 'react'
import { useLocale, useTranslations } from 'next-intl'
import { saveAvailability, deleteAvailability } from '@/app/[locale]/dashboard/availability/actions'
import type { AthleteAvailabilitySlot } from '@/types/database'
import { Modal } from '@/components/Modal'
import { Segments } from '@/components/Segments'
import { DatePickerPopup } from '@/components/DatePickerPopup'
import { Button } from '@/components/Button'
import { Textarea } from '@/components/Textarea'
import { Dropdown } from '@/components/Dropdown'
import { formatDateFr, toDateStr } from '@/lib/dateUtils'
import { FORM_INPUT_HEIGHT, FORM_INPUT_TEXT_SIZE } from '@/lib/formStyles'

/** Options horaires par pas de 15 min (00:00 à 23:45). */
function getTimeOptions(): { value: string; label: string }[] {
  const options: { value: string; label: string }[] = [{ value: '', label: '—' }]
  for (let h = 0; h < 24; h++) {
    for (let m = 0; m < 60; m += 15) {
      options.push({
        value: `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`,
        label: `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`,
      })
    }
  }
  return options
}

const TIME_OPTIONS = getTimeOptions()

type AvailabilityModalProps = {
  isOpen: boolean
  onClose: (closedBySuccess?: boolean) => void
  date: string
  athleteId: string
  pathToRevalidate: string
  /** En mode édition : pré-remplit le formulaire et enregistre via update (pas de récurrence). */
  editSlot?: AthleteAvailabilitySlot | null
}

function SubmitButton({ disabled, isSubmitting, showSuccess }: { disabled?: boolean; isSubmitting?: boolean; showSuccess?: boolean }) {
  const { pending } = useFormStatus()
  const t = useTranslations('common')
  return (
    <Button
      type="submit"
      form="availability-form"
      variant="primaryDark"
      disabled={disabled || pending || isSubmitting}
      loading={pending || isSubmitting}
      loadingText={t('saving')}
      success={showSuccess}
      successText={t('saved')}
      className="flex-1 min-w-0"
    >
      {t('save')}
    </Button>
  )
}

export function AvailabilityModal({
  isOpen,
  onClose,
  date,
  athleteId,
  pathToRevalidate,
  editSlot = null,
}: AvailabilityModalProps) {
  const locale = useLocale()
  const localeForPicker = locale === 'fr' ? 'fr-FR' : 'en-US'
  const t = useTranslations('availability')
  const tCommon = useTranslations('common')

  const [typeSegment, setTypeSegment] = useState<'available' | 'unavailable' | ''>('')
  const [editableDate, setEditableDate] = useState(date)
  const [startTime, setStartTime] = useState('')
  const [endTime, setEndTime] = useState('')
  const [note, setNote] = useState('')

  const [showDatePickerPopup, setShowDatePickerPopup] = useState(false)
  const dateTriggerRef = useRef<HTMLDivElement>(null)
  const [datePickerAnchor, setDatePickerAnchor] = useState<DOMRect | null>(null)

  const [showSavedFeedback, setShowSavedFeedback] = useState(false)
  const previousSubmittingRef = useRef(false)
  const previousPendingRef = useRef(false)
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false)
  const initialValuesRef = useRef({ typeSegment, editableDate, startTime, endTime, note })
  const [deleteLoading, setDeleteLoading] = useState(false)
  const [deleteError, setDeleteError] = useState<string | null>(null)

  const [state, action, isPending] = useActionState(
    async (prev: { error?: string; success?: boolean }, fd: FormData) =>
      saveAvailability(athleteId, pathToRevalidate, prev, fd),
    {} as { error?: string; success?: boolean }
  )

  const isEditMode = !!editSlot

  useEffect(() => {
    if (isOpen) {
      setDeleteError(null)
      previousPendingRef.current = false
      if (editSlot) {
        setEditableDate(editSlot.date)
        setTypeSegment(editSlot.type)
        setStartTime(editSlot.start_time ?? '')
        setEndTime(editSlot.end_time ?? '')
        setNote(editSlot.note ?? '')
        initialValuesRef.current = {
          typeSegment: editSlot.type,
          editableDate: editSlot.date,
          startTime: editSlot.start_time ?? '',
          endTime: editSlot.end_time ?? '',
          note: editSlot.note ?? '',
        }
      } else {
        setEditableDate(date)
        setTypeSegment('')
        setStartTime('')
        setEndTime('')
        setNote('')
        initialValuesRef.current = {
          typeSegment: '',
          editableDate: date,
          startTime: '',
          endTime: '',
          note: '',
        }
      }
      setHasUnsavedChanges(false)
    }
  }, [isOpen, date, editSlot])

  useEffect(() => {
    if (previousSubmittingRef.current && !(isPending || state?.success)) {
      setShowSavedFeedback(true)
      const t = setTimeout(() => setShowSavedFeedback(false), 2500)
      return () => clearTimeout(t)
    }
    previousSubmittingRef.current = !!isPending || !!state?.success
  }, [isPending, state?.success])

  useEffect(() => {
    const current = { typeSegment, editableDate, startTime, endTime, note }
    const init = initialValuesRef.current
    const changed =
      current.typeSegment !== init.typeSegment ||
      current.editableDate !== init.editableDate ||
      current.startTime !== init.startTime ||
      current.endTime !== init.endTime ||
      current.note !== init.note
    setHasUnsavedChanges(changed)
  }, [typeSegment, editableDate, startTime, endTime, note])

  const openDatePicker = () => {
    dateTriggerRef.current?.getBoundingClientRect && setDatePickerAnchor(dateTriggerRef.current.getBoundingClientRect())
    setShowDatePickerPopup(true)
  }
  const closeDatePicker = () => {
    setShowDatePickerPopup(false)
    setDatePickerAnchor(null)
  }

  const handleClose = () => {
    if (state?.success) {
      onClose(true)
    } else {
      onClose(false)
    }
  }

  // Fermer la modale quand une soumission vient de se terminer avec succès.
  // Important : `useActionState` peut conserver `state.success` entre ouvertures,
  // donc on se base sur la transition pending -> not pending.
  const closeFeedbackKey = `${state?.success ?? ''}|${state?.error ?? ''}|${isPending}`
  useEffect(() => {
    const justFinished = previousPendingRef.current && !isPending
    previousPendingRef.current = isPending

    if (state?.success && justFinished) {
      const t = setTimeout(() => onClose(true), 500)
      return () => clearTimeout(t)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [closeFeedbackKey])

  const dateBlock = (
    <div
      ref={dateTriggerRef}
      className={`flex items-center gap-2 border border-stone-300 rounded-lg py-2.5 px-4 bg-white focus-within:ring-2 focus-within:ring-palette-forest-dark focus-within:border-transparent transition ${FORM_INPUT_TEXT_SIZE} ${FORM_INPUT_HEIGHT}`}
    >
      <span className="text-sm font-bold text-stone-900 min-w-[10rem]" aria-hidden>
        {formatDateFr(editableDate, true, localeForPicker)}
      </span>
      <button
        type="button"
        onClick={openDatePicker}
        className="shrink-0 p-1 rounded text-stone-400 hover:text-palette-forest-dark hover:bg-stone-100"
        title={t('until')}
        aria-label={t('until')}
      >
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
      </button>
    </div>
  )

  const datePickerPopover =
    showDatePickerPopup && datePickerAnchor && typeof document !== 'undefined'
      ? createPortal(
          <>
            <div className="fixed inset-0 z-[105]" aria-hidden onClick={closeDatePicker} />
            <div
              className="fixed z-[110] shadow-xl"
              style={{ top: datePickerAnchor.bottom + 8, left: datePickerAnchor.left }}
              onClick={(e) => e.stopPropagation()}
            >
              <DatePickerPopup
                value={editableDate}
                onChange={(dateStr) => {
                  setEditableDate(dateStr)
                  closeDatePicker()
                }}
                locale={localeForPicker}
                minDate={toDateStr(new Date())}
                monthDropdownId="availability-date-picker-month"
              />
            </div>
          </>,
          document.body
        )
      : null

  const handleDelete = async () => {
    if (!editSlot) return
    if (!confirm(t('confirmDelete'))) return
    setDeleteError(null)
    setDeleteLoading(true)
    const result = await deleteAvailability(athleteId, pathToRevalidate, editSlot.id)
    setDeleteLoading(false)
    if (result.error) {
      setDeleteError(result.error)
      return
    }
    onClose(true)
  }

  return (
    <>
      {datePickerPopover}
      <Modal
        isOpen={isOpen}
        onClose={handleClose}
        size="workout"
        title={undefined}
        icon={dateBlock}
        iconRaw
        titleId="availability-modal-title"
        contentClassName="px-6 py-4"
        footer={
          <div className="w-full">
            {(state?.error || deleteError) && (
              <p className="text-sm text-palette-danger mb-3" role="alert">
                {state?.error ?? deleteError}
              </p>
            )}
            <div className="flex gap-3 items-center">
              {!isEditMode && (
                <Button type="button" variant="muted" onClick={() => onClose(false)} className="flex-1 min-w-0">
                  {tCommon('cancel')}
                </Button>
              )}
              {isEditMode && editSlot && (
                <Button
                  type="button"
                  variant="danger"
                  onClick={handleDelete}
                  disabled={deleteLoading}
                  loading={deleteLoading}
                  loadingText={tCommon('deleting')}
                  className="flex-1 min-w-0 flex items-center justify-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                  {t('delete')}
                </Button>
              )}
              <SubmitButton disabled={!hasUnsavedChanges || typeSegment === ''} isSubmitting={isPending} showSuccess={showSavedFeedback} />
            </div>
          </div>
        }
      >
        <form id="availability-form" action={action} className="space-y-5">
          {isEditMode && editSlot && <input type="hidden" name="slot_id" value={editSlot.id} readOnly aria-hidden />}
          <input type="hidden" name="date" value={editableDate} readOnly aria-hidden />
          <input type="hidden" name="type" value={typeSegment} readOnly aria-hidden />
          <input type="hidden" name="start_time" value={startTime} readOnly aria-hidden />
          <input type="hidden" name="end_time" value={endTime} readOnly aria-hidden />
          <input type="hidden" name="note" value={note} readOnly aria-hidden />

          <div>
            <Segments
              name="availability-type"
              options={[
                { value: 'available', label: t('available') },
                { value: 'unavailable', label: t('unavailable') },
              ]}
              value={typeSegment}
              onChange={(v) => { setTypeSegment(v as 'available' | 'unavailable'); setHasUnsavedChanges(true) }}
              ariaLabel={t('type')}
            />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <Dropdown
              id="availability-start"
              label={t('start')}
              options={TIME_OPTIONS}
              value={startTime}
              onChange={setStartTime}
              ariaLabel={t('start')}
            />
            <Dropdown
              id="availability-end"
              label={t('end')}
              options={TIME_OPTIONS}
              value={endTime}
              onChange={setEndTime}
              ariaLabel={t('end')}
            />
          </div>

          <div>
            <Textarea
              label={t('note')}
              placeholder={t('notePlaceholder')}
              value={note}
              onChange={(e) => setNote(e.target.value)}
              rows={3}
            />
          </div>
        </form>
      </Modal>
    </>
  )
}

