  /** Formate une heure "HH:mm" pour affichage (ex. "08h", "08h30"). */
  const formatTimeDisplay = (timeStr: string) => {
    const [h, m] = timeStr.split(':').map(Number)
    if (m === 0) return `${String(h).padStart(2, '0')}h`
