              {currentWorkout.athlete_comment?.trim() ? currentWorkout.athlete_comment : tWorkouts('comments.noComment')}
            </p>
          </div>
        </div>
      </div>
      ) : (
      <form
        id="workout-form"
        action={action}
        className={`flex flex-col flex-1 min-h-0 ${!canEdit ? 'select-none' : ''}`}
        onSubmit={(e) => {
